Also add some code in `conda.common` to parse conda's flavor of json streams, which separate json objects with a NULL character.  Something like

```python
def maybe_json_loads(string):
    try:
        return json.loads(string)
    except Exception as e:
        log.warn(
            "Problem parsing json output.\n"
            "  output: %s\n"
            "  error: %r",
            string, e
        )


def parse_conda_streaming_json(file_handle):
    chunks = []
    for chunk in iter(partial(file_handle.read, 8192), b''):
        if '\0' not in chunk:
            chunks.append(chunk)
            continue

        parts = chunk.split('\0')
        parts_limit = len(parts) - 1
        for q, part in enumerate(parts):
            if q == 0:
                string = ''.join(chain.from_iterable((chunks, (part,))))
                yield maybe_json_loads(string)
                chunks = []
            elif q == parts_limit:
                chunks.append(part)
            else:
                yield maybe_json_loads(part)
```

